"https://vz-cfbc9d86-eae.b-cdn.net/ceaa3985-6edf-46b1-b484-154592486db7/play_720p.mp4?token=QHsM1TRjgFoVFBodCFYUeQ&token_path=%2Fceaa3985-6edf-46b1-b484-154592486db7%2F&expires=1781159178","videoHlsUrl":"https://vz-cfbc9d86-eae.b-cdn.net/ceaa3985-6edf-46b1-b484-154592486db7/playlist.m3u8?token=QHsM1TRjgFoVFBodCFYUeQ&token_path=%2Fceaa3985-6edf-46b1-b484-154592486db7%2F&expires=1781159178","thumbnailUrl":"https://exercise-api.ymove.app/api/v2/thumbnail/ceaa3985-6edf-46b1-b484-154592486db7?library=clean","videos":[{"videoUrl":"https://vz-cfbc9d86-eae.b-cdn.net/ceaa3985-6edf-46b1-b484-154592486db7/play_720p.mp4?token=QHsM1TRjgFoVFBodCFYUeQ&token_path=%2Fceaa3985-6edf-46b1-b484-154592486db7%2F&expires=1781159178","videoHlsUrl":"https://vz-cfbc9d86-eae.b-cdn.net/ceaa3985-6edf-46b1-b484-154592486db7/playlist.m3u8?token=QHsM1TRjgFoVFBodCFYUeQ&token_path=%2Fceaa3985-6edf-46b1-b484-154592486db7%2F&expires=1781159178","thumbnailUrl":"https://exercise-api.ymove.app/api/v2/thumbnail/ceaa3985-6edf-46b1-b484-154592486db7?library=clean","tag":"white-background","orientation":"landscape","isPrimary":true}]},{"id":"c4d91f02-e796-4992-a08d-531b1d4bb16b","title":"Bear crawl shoulder tap to pike push up","slug":"bear-crawl-shoulder-tap-to-pike-push-up","description":"Starting position: Begin in a bear crawl position with hands planted shoulder-width apart, knees hovering just above the ground, and core engaged. Execution: Perform a shoulder tap by lifting one hand to touch the opposite shoulder, then transition into a pike position and perform a push-up before returning to the starting bear crawl position.","instructions":["Start in bear crawl position with hands shoulder-width apart and knees hovering 2-3 inches off the ground","Lift your right hand and tap your left shoulder while maintaining balance on three points of contact","Return your right hand to the ground, then repeat the shoulder tap with your left hand to right shoulder","While keeping legs straight to transition into a downward dog or pike position","Perform one pike push-up by lowering your head toward the ground between your hands and pressing back up","Walk your feet back out to return to the starting bear crawl position and repeat the sequence"],"importantPoints":["Keep your core tight throughout the entire movement to maintain stability and protect your lower back","Minimize hip rotation during shoulder taps by engaging your glutes and maintaining a strong plank position","Focus on controlled movements rather than speed to maximize muscle engagement and reduce injury risk","Ensure proper pike push-up form by keeping your legs straight and targeting the shoulders rather than letting your hips sag","Start with fewer repetitions and build up gradually as this exercise requires significant upper body and core strength"],"muscleGroup":"chest","secondaryMuscles":null,"equipment":"bodyweight","category":"Chest","difficulty":"intermediate","videoDurationSecs":null,"hasVideo":true,"hasVideoWhite":true,"hasVideoGym":false,"exerciseType":["strength","calisthenics","functional"],"videoUrl":"https://vz-cfbc9d86-eae.b-cdn.net/546d8a4f-1539-4c53-bdb7-20271c04524d/play_720p.mp4?token=BwVKr3SqCBI6aqWRiJgT0A&token_path=%2F546d8a4f-1539-4c53-bdb7-20271c04524d%2F&expires=1781159178","videoHlsUrl":"https://vz-cfbc9d86-eae.b-cdn.net/546d8a4f-1539-4c53-bdb7-20271c04524d/playlist.m3u8?token=BwVKr3SqCBI6aqWRiJgT0A&token_path=%2F546d8a4f-1539-4c53-bdb7-20271c04524d%2F&expires=1781159178","thumbnailUrl":"https://exercise-api.ymove.app/api/v2/thumbnail/546d8a4f-1539-4c53-bdb7-20271c04524d?library=clean","videos":[{"videoUrl":"https://vz-cfbc9d86-eae.b-cdn.net/546d8a4f-1539-4c53-bdb7-20271c04524d/play_720p.mp4?token=BwVKr3SqCBI6aqWRiJgT0A&token_path=%2F546d8a4f-1539-4c53-bdb7-20271c04524d%2F&expires=1781159178","videoHlsUrl":"https://vz-cfbc9d86-eae.b-cdn.net/546d8a4f-1539-4c53-bdb7-20271c04524d/playlist.m3u8?token=BwVKr3SqCBI6aqWRiJgT0A&token_path=%2F546d8a4f-1539-4c53-bdb7-20271c04524d%2F&expires=1781159178","thumbnailUrl":"https://exercise-api.ymove.app/api/v2/thumbnail/546d8a4f-1539-4c53-bdb7-20271c04524d?library=clean","tag":"white-background","orientation":"landscape","isPrimary":true}]},{"id":"accf9858-fd32-4f43-aa4d-0bd0f53d7498","title":"Bear crawl to pike push up","slug":"bear-crawl-to-pike-push-up","description":"Starting position: Begin in a bear crawl position with hands and feet on the ground, knees hovering just above the floor, maintaining a straight back. Execution: Crawl forward 3-4 steps, then walk your feet toward your hands while keeping legs straight, transitioning into a downward dog position before performing a pike push-up by lowering your head toward the ground between your hands.","instructions":["Start in bear crawl position with hands shoulder-width apart, core engaged, and knees hovering 2-3 inches off the ground","Take 3-4 controlled steps forward, moving opposite hand and foot together while maintaining neutral spine","Stop crawling and begin walking your feet toward your hands, keeping legs as straight as possible","Continue until you reach an inverted V position with weight distributed between hands and feet","Lower your head toward the ground between your hands by bending your elbows, keeping them close to your body","Push back up to the pike position and repeat the sequence"],"importantPoints":["Keep your core tight throughout the entire movement to protect your lower back and maintain proper form","Maintain steady breathing and avoid holding your breath during the transition from bear crawl to pike position","Focus on controlled movements rather than speed, especially when transitioning between positions","Ensure adequate shoulder mobility before attempting pike push-ups, as this exercise requires significant overhead shoulder flexibility","Start with fewer repetitions and gradually increase as your strength and coordination improve"],"muscleGroup":"chest","secondaryMuscles":null,"equipment":"bodyweight","category":"Chest","difficulty":"intermediate","videoDurationSecs":null,"hasVideo":true,"hasVideoWhite":true,"hasVideoGym":false,"exerciseType":["strength","calisthenics","functional"],"videoUrl":"https://vz-cfbc9d86-eae.b-cdn.net/b07a2978-86db-4752-b7a6-5e6a313f926a/play_720p.mp4?token=lN6_3w6Lvajn3yakNOvilQ&token_path=%2Fb07a2978-86db-4752-b7a6-5e6a313f926a%2F&expires=1781159178","videoHlsUrl":"https://vz-cfbc9d86-eae.b-cdn.net/b07a2978-86db-4752-b7a6-5e6a313f926a/playlist.m3u8?token=lN6_3w6Lvajn3yakNOvilQ&token_path=%2Fb07a2978-86db-4752-b7a6-5e6a313f926a%2F&expires=1781159178","thumbnailUrl":"https://exercise-api.ymove.app/api/v2/thumbnail/b07a2978-86db-4752-b7a6-5e6a313f926a?library=clean","videos":[{"videoUrl":"https://vz-cfbc9d86-eae.b-cdn.net/b07a2978-86db-4752-b7a6-5e6a313f926a/play_720p.mp4?token=lN6_3w6Lvajn3yakNOvilQ&token_path=%2Fb07a2978-86db-4752-b7a6-5e6a313f926a%2F&expires=1781159178","videoHlsUrl":"https://vz-cfbc9d86-eae.b-cdn.net/b07a2978-86db-4752-b7a6-5e6a313f926a/playlist.m3u8?token=lN6_3w6Lvajn3yakNOvilQ&token_path=%2Fb07a2978-86db-4752-b7a6-5e6a313f926a%2F&expires=1781159178","thumbnailUrl":"https://exercise-api.ymove.app/api/v2/thumbnail/b07a2978-86db-4752-b7a6-5e6a313f926a?library=clean","tag":"white-background","orientation":"landscape","isPrimary":true}]},{"id":"58d0fe05-1a66-4b80-a6d8-2dc2f0d73169","title":"Bench Press","slug":"bench-press","description":"Starting position: Lie on a flat bench with a barbell in your hands, arms extended upward with an overhand grip. Execution: Lower the bar to your chest, then press upward to return to the starting position.","instructions":["Position bench under bar","Align bar over mid-chest","Unrack, lower bar to chest","Press up to full extension (don't lock)","Repeat for reps, rack safely"],"importantPoints":["Bar path is fixed - position bench properly","Keep feet flat on floor","Shoulder blades squeezed","Control the descent","Good for training to failure (can rack anytime)"],"muscleGroup":"chest","secondaryMuscles":[],"